var settings = require('./settings');
var i18n = require('i18next');
var jqueryI18next = require('jquery-i18next');
var backend = require("i18next-http-backend");
var lngDetector = require('i18next-browser-languagedetector');
var cache = require('i18next-localstorage-cache');
var Url = require('domurl');
var Cookies = require('js-cookie');

const backOpts = {
  loadPath: "$_LOCALES_URL/locales/{{lng}}/{{ns}}", // in the original .json

  crossDomain: true,
}

var currentUrl  = new Url;

const laSessionCookie = 'la-lang-session';

const i18nOpts = {
  backend: backOpts,
  fallbackLng: {
    zh: ['en'],
    "sw-TZ": ['en'],
    default: ['en']
  },
  sendMissingTo: 'fallback',
  interpolation: {
    escapeValue: false,
    formatSeparator: ',',
    format: function f(value, format, lng) {
      if (format === 'uppercase') return value.toUpperCase();
      if (value instanceof Date) return moment(value).format(format);
      if (format === 'number') return Intl.NumberFormat(lng).format(value);
      return value;
    }
  },
  whitelist: settings.enabledLangs,
  load: 'languageOnly', // 'es' o 'en', previously: 'all', // es-ES -> es, en-US -> en
  debug: true,
  ns: 'common',
  defaultNS: 'common',
  saveMissing: true, // if true seems it's fails to getResourceBundle
  saveMissingTo: 'en',
  keySeparator: 'ß',
  nsSeparator: 'ð',
  pluralSeparator: 'đ'
};

const detectorOptions = {
  order: ['querystring', 'cookie', 'navigator', 'localStorage', 'htmlTag'],

  lookupQuerystring: 'lang',
  lookupCookie: 'i18next',
  lookupLocalStorage: 'i18nextLng',
  cookieMinutes: 525600, // a year
  caches: ['cookie'],
  excludeCacheFor: ['cimode'] // languages to not persist (cookie, localStorage)
};

if (document.location.host !== 'localhost:3333') {
  detectorOptions.cookieDomain = settings.mainDomain;
}

const cacheOptions = {
  enabled: false,
  prefix: 'i18next_res_',
  expirationTime: 7 * 24 * 60 * 60 * 1000,
  versions: {}
};

i18nOpts.cache = cacheOptions;
i18nOpts.detection = detectorOptions;

i18nOpts.sendMissing = false;
i18nOpts.missingKeyHandler = function miss(lng, ns, key, defaultValue) {
  console.log(`"${key}": "${defaultValue}"`);
};

i18n.on('languageChanged', function (lng) {
  if (i18n.services.languageDetector) {
    console.log(`On lang changed ${lng}`);
    i18n.services.languageDetector.cacheUserLanguage(lng);
  }
});

(function($) {
i18n.use(backend)
    .use(lngDetector)
    .use(cache)
    .init(i18nOpts, (err, t) => {
      if (err) {
        console.error(err);
        return;
      }
      console.log(`Language initialized: ${i18n.language}`);
      jqueryI18next.init(i18n, $, { i18nName: 'i18next' } );
      console.log('jquery i18next initialized');
      $("body").localize();

      $('.locale-link').on('click', function(e) {
        e.preventDefault();
        const lang = $(this).data('locale');
        console.log(`Lang clicked ${lang}`);

        i18n.changeLanguage(lang);

        currentUrl.query.lang = lang;
        document.location.search = currentUrl.query;
      });
      if( $('#dropdown-lang').length ) {
        $('#dropdown-lang').find('.dropdown-toggle').html(i18n.language + ' <span class="caret"></span>');
      }

      if (typeof Cookies.get(laSessionCookie) === 'undefined' && typeof currentUrl.query.lang === 'undefined') {
        var in30Minutes = 1/48;
        Cookies.set(laSessionCookie, '/', { expires: in30Minutes });
        currentUrl.query.lang = i18n.language;
        document.location.search = currentUrl.query;
      }

    });
}(jQuery));

var settings = require('./settings');
var bieService = settings.services.bieService.url;


window.BC_CONF = window.BC_CONF || {};
BC_CONF.autocompleteURL = `${bieService}/search/auto.json`

var Cookies = require("js-cookie");
const settings = require("js/settings");
const authCookieName = "ALA-Auth";
const loginClass = "signedIn";
const logoutClass = "signedOut";

var loginStatusInIndex = () => {
  if (
    (document.location.origin === settings.mainLAUrl ||
      document.location.host === "localhost:3333") &&
    document.location.pathname === "/"
  ) {
    if (settings.isDevel)
      console.log("We are in the main url, let's see if we are authenticated");

    let authCookie = Cookies.get(authCookieName, {
      domain: settings.mainDomain,
      path: "/",
    });
    var in30Minutes = 1 / 48;

    if (
      typeof authCookie === "undefined" &&
      document.location.host === "localhost:3333"
    ) {
      console.log("We set a test cookie if we are in development");
      Cookies.set(authCookieName, "/", { expires: in30Minutes });
    }

    if (typeof authCookie !== "undefined") {
      if (settings.isDevel) console.log("Auth cookie present so logged in");
      $("#dropdown-auth-menu")
        .removeClass("::loginStatus::")
        .addClass("signedIn");
    } else {
      if (settings.isDevel)
        console.log("No auth cookie not present so not-logged in");
      $("#dropdown-auth-menu")
        .removeClass("::loginStatus::")
        .addClass("signedOut");
    }
  } else {
    if (settings.isDevel) console.log("We aren't in the main url");
  }
};

$(function () {
  var checkExist = setInterval(function () {
    if (window.jQuery && $("#dropdown-auth-menu").length) {
      clearInterval(checkExist);
      loginStatusInIndex();
    } else {
      if (settings.isDevel) console.log("drawer not loaded");
    }
  }, 1000);
});

var settings = require('./settings');

$(function(){
  if (settings.inMante) {
    console.log("Setting manteinance banner");

    var manteDiv = `<div class="row">
    <div class="col-md-6">
      <div class="error-template">
        <h1 data-i18n="error.title"></h1>
        <h2 data-i18n="error.subtitle"></h2>
        <div>
          <p data-i18n="error.description"></p>
        </div>
        <div class="error-actions">
          <a data-i18n="error.button" href="${settings.mainLAUrl}" style="margin-top: 10px;" class="btn btn-primary btn-lg"></a>
        </div>
      </div>
    </div>
    <div class="col-md-6">
      <img src="images/error.svg" alt="Error Image" onerror="this.onerror=null; this.src='images/error.png'">
    </div>
  </div>`;
    $("#mante-container").html(manteDiv);
    $("#mante-container").show();
  }
});

var settings = require('./settings');
var { CountUp } = require('countup.js');

var collectory = settings.services.collectory.url;
var biocacheService = settings.services.biocacheService.url;

var setCounter = (id, val, onEnd) => {
  const options = {
    separator: ',', // FIXME  locale === 'en' ? ',': '.',
    duration: 1
  };
  if (val === 0 && settings.isDevel) {
    val = 123456;
  }
  options.startVal = Math.round(val - val * 4/100); // we increment only a %
  console.log(`Start val ${options.startVal} to ${val}`);
  const countUp = new CountUp(id, val, options);
  if (!countUp.error) {
    countUp.start(() => { $(`#${id}`).addClass('loaded_stats'); if (typeof onEnd !== 'undefined') onEnd(); });
  } else {
    console.error(countUp.error);
  }
};

var getStats = (url, callback) => {
  if (settings.isDevel) {
    if (url.indexOf('species') > -1) callback([{ count: 10402 }]);
    else callback({ totalRecords: 86965283, total: 12922 });
  } else {
    $.getJSON(url, callback);
  }
}

var loadStats = () => {
  getStats(`${biocacheService}/occurrences`, (data) => {
    setCounter('stats_occurrences', data.totalRecords, () =>
      getStats(`${collectory}/ws/dataResource/count`, (data) => {
        setCounter('stats_datasets', data.total, () =>
          getStats(`${collectory}/ws/institution/count`, (data) => {
            setCounter('stats_institutions', data.total);
          })
        )
      })
    )});
  getStats(`${biocacheService}/occurrence/facets?q=*:*&facets=species&pageSize=0`, (data) => {
    setCounter("stats_species", data[0].count);
  });
}

document.addEventListener("DOMContentLoaded", () => {
  if ((document.location.origin === settings.mainLAUrl || document.location.host === 'localhost:3333') && document.location.pathname === '/' ) {
    loadStats();
  }
});

