function additionalToolkitPrompts() {
  let addPrompt = [];
  for (let variable in additionalToolkitVariables) {
    addPrompt.push({ store: true, when: (a) => false, type: 'input', name: variable });
  }
  return addPrompt;
}

export {
  defUseSubdomain,
  defUseSubdomainPrompt,
  isCorrectDomain,
